var getSneakyNumbers = function(nums) {
    const n = nums.length - 2;
    const count = new Array(n).fill(0);
    const result = [];
    for (const x of nums) {
        count[x]++;
        if (count[x] === 2) result.push(x);
    }
    result.sort((a, b) => a - b);
    return result;
};
